import Form from 'react-bootstrap/Form';
import React, { useState, useCallback, useEffect } from "react";
import Gallery from "react-photo-gallery";
import Carousel, { Modal, ModalGateway } from "react-images";
import Button from 'react-bootstrap/Button'

function App() {
  const [currentImage, setCurrentImage] = useState(0);
  const [viewerIsOpen, setViewerIsOpen] = useState(false);
  const [photos,setPhotos] = useState([]);
  const [page,setPage] = useState(1);
  const [text,setText] = useState('nature');

  const openLightbox = useCallback((event, { photo, index }) => {
    setCurrentImage(index);
    setViewerIsOpen(true);
  }, []);

  const closeLightbox = () => {
    setCurrentImage(0);
    setViewerIsOpen(false);
  };

  useEffect(() => doRequest(page), []);

  const nextPage = () => {
    let newPage = page+1;
    setPage(newPage);
    doRequest(newPage);
    //window.scrollTo(0, 0);
  }
  const search = (e) => {
    
    if(e.key === 'Enter'){
      setPage(1);
      photos.length = 0;
      setPhotos(photos)
      
      doRequest()

    }
  }
  const doRequest = (pageNO) => {
    fetch(`https://pixabay.com/api/?q=${text}&key=6430172-09d836b2d3bf7a1e65bb04b07&image_type=photo&pretty=false&per_page=20&page=${pageNO}`)
    .then(res => res.json())
    .then(
      (results) => {
        var images = [];
        results.hits.forEach(item => {
          images.push({
            "height" : item.imageHeight,
            "width" : item.imageWidth,
            "src" : item.largeImageURL
          });
        });
        setPhotos([...photos, ...images]);
      },
      (error) => {}
    )
  }
  return (
    
    <div className="page">
      <div className="page-header">
         
        <div className="search-box">
          <h1 className="app-name">
            React Js, Pixabay Image Gallery
          </h1> 
          <Form.Control type="text" placeholder="Enter text to serach and hit enter" className="search-input" onChange={(e) => setText(e.target.value)} onKeyDown={search}/>
        </div>  
      </div>
      <hr />
      <div className="images" >
      <Gallery photos={photos} onClick={openLightbox} />
      <div className="text-center">
        <Button variant="info" onClick={nextPage}>Load More Images</Button>
      </div> 
      <ModalGateway>
        {viewerIsOpen ? (
          <Modal onClose={closeLightbox}>
            <Carousel
              currentIndex={currentImage}
              views={photos.map(x => ({
                ...x,
                srcset: x.srcSet,
                caption: x.title
              }))}
            />
          </Modal>
        ) : null}
      </ModalGateway>
      </div>
    </div>
  );
}
export default App;